3	type Scenario = {
4	  steps: Array<{ op: "quote"; items: unknown[] }>;
5	};
6	
7	const quotePremium = (items: unknown[]): number => {
8	  if (items.length === 0) return PROCESSING_FEE_G;
9	  return 60;
10	};
11	
12	export const runScenario = (scenario: unknown): unknown => {
13	  const items = (scenario as Scenario).steps[0].items;
14	  return { results: [{ premium: quotePremium(items) }] };
15	};
