32	  it.todo("4 runes → base premium 100 G (no block — exactly 3 required)");
33	  it.todo("7 runes → base premium 175 G (no block — not a multiple-of-3 special case)");
34	
35	  // Alike components — clarifying question
36	  it.todo("2 runes + 1 moonstone → base premium 75 G (no block: different types)");
37	  it.todo("3 runes + 3 moonstones → base premium 120 G (two separate blocks)");
38	
39	  // Modifier scope on multi-item policies — clarifying question
40	  it.todo("policy: cursed sword + plain amulet → 210 G before further modifiers and fee (cursed surcharge only on cursed item)");
41	
