50	  it.todo("premium calculation yielding 197.5 G → 198 G (rounded up)");
51	  it.todo("payout calculation yielding 350.5 G → 350 G (rounded down)");
52	
53	  // Integration examples (premium)
54	  it.todo("newcomer with cursed sword (steel, enchantment 3) → premium 165 G");
55	  it.todo("long-standing customer's second contract: cursed sword (steel, enchantment 7), 3 years → premium 160 G");
